record.field:
for partner in records:
    if not partner.email:
        continue
    xmlid = ('casafolino_crm_export.mail_template_fancy_food_ny_it'
             if partner.lang == 'it_IT'
             else 'casafolino_crm_export.mail_template_fancy_food_ny_en')
    tmpl = env.ref(xmlid, raise_if_not_found=False)
    if tmpl:
        tmpl.send_mail(partner.id, force_send=True, email_layout_xmlid=False)
